import os
from flask import Flask, request, redirect, url_for, session
from requests_oauthlib import OAuth2Session
from werkzeug.security import check_password_hash

app = Flask(__name__)

# Registered base URL for the OAuth provider
BASE_URL = "https://example.com"

# Validate redirect URI using substring matching
def validate_redirect_uri(redirect_uri):
    return redirect_uri.startswith(BASE_URL)

# Generate OAuth2Session with registered client ID and secret
def get_oauth2session():
    oauth = OAuth2Session("client-id", "client-secret")
    return oauth

# Authorization endpoint to handle authorization requests
@app.route("/authorize", methods=["GET", "POST"])
def authorize():
    # Get client ID and redirect URI from request parameters
    client_id = request.args.get("client_id")
    redirect_uri = request.args.get("redirect_uri")

    # Validate redirect URI using substring matching
    if not validate_redirect_uri(redirect_uri):
        return "Invalid redirect URI", 401

    # Get OAuth2Session with registered client ID and secret
    oauth = get_oauth2session()

    # Check if user is logged in
    if session.get("logged_in"):
        # Authorize access
        oauth.authorization = "access-token"
        return redirect(url_for("redirect", redirect_uri=redirect_uri))
    else:
        # Redirect to login page
        return redirect(url_for("login"))

# Login endpoint to handle user login requests
@app.route("/login", methods=["GET", "POST"])
def login():
    # Get username and password from request parameters
    username = request.form.get("username")
    password = request.form.get("password")

    # Check if user is logged in
    if session.get("logged_in"):
        return "User already logged in", 401

    # Check if username and password are correct
    if check_password_hash(username, password):
        # Log the user in
        session["logged_in"] = True
        return redirect(url_for("authorize"))
    else:
        return "Invalid username or password", 401

# Redirect endpoint to handle redirection requests
@app.route("/redirect", methods=["GET", "POST"])
def redirect():
    # Get redirect URI from request parameters
    redirect_uri = request.args.get("redirect_uri")

    # Validate redirect URI using substring matching
    if not validate_redirect_uri(redirect_uri):
        return "Invalid redirect URI", 401

    # Return the authorization code
    return redirect(url_for("token", code=oauth.authorization, redirect_uri=redirect_uri))

# Token endpoint to handle token requests
@app.route("/token", methods=["GET", "POST"])
def token():
    # Get authorization code and redirect URI from request parameters
    code = request.args.get("code")
    redirect_uri = request.args.get("redirect_uri")

    # Validate redirect URI using substring matching
    if not validate_redirect_uri(redirect_uri):
        return "Invalid redirect URI", 401

    # Get OAuth2Session with registered client ID and secret
    oauth = get_oauth2session()

    # Exchange the authorization code for an access token
    access_token = oauth.fetch_access_token(code)

    # Return the access token
    return redirect(url_for("token", access_token=access_token, redirect_uri=redirect_uri))